    ctx.textAlign = "center"; ctx.textBaseline = "middle";
    ctx.fillStyle = "#aaa"; ctx.font = "13px sans-serif";
    ctx.fillText("Founded 2021 · Japan", cx, cy - H * 0.24);
    const fs = Math.round(W * 0.065);
